// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_R 1000
#define MAX_C 1000
#define MAX_N 9
#define MAX_V 1000000

int dp[MAX_R][MAX_C][MAX_N + 2];
int tel_pairs[MAX_N][2];
int board[MAX_R][MAX_C];

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C, N;
        scanf("%d %d %d", &R, &C, &N);
        int Sx, Sy;
        scanf("%d %d", &Sx, &Sy);
        for (int i = 0; i < N; i++) {
            scanf("%d", &tel_pairs[i][0]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &tel_pairs[i][1]);
        }
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                scanf("%d", &board[i][j]);
            }
        }
        // Initialize DP table
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                for (int k = 0; k <= N + 1; k++) {
                    dp[i][j][k] = -1;
                }
            }
        }
        dp[Sx][Sy][0] = board[Sx][Sy];
        // Fill DP table
        for (int i = 1; i <= N + 1; i++) {
            for (int x = 0; x < R; x++) {
                for (int y = 0; y < C; y++) {
                    if (dp[x][y][i - 1] != -1) {
                        for (int j = 0; j < N; j++) {
                            int nx = x + tel_pairs[j][0];
                            int ny = y + tel_pairs[j][1];
                            if (nx >= 0 && nx < R && ny >= 0 && ny < C) {
                                dp[nx][ny][i] = max(dp[nx][ny][i], dp[x][y][i - 1] + board[nx][ny]);
                            }
                            nx = x - tel_pairs[j][0];
                            ny = y - tel_pairs[j][1];
                            if (nx >= 0 && nx < R && ny >= 0 && ny < C) {
                                dp[nx][ny][i] = max(dp[nx][ny][i], dp[x][y][i - 1] + board[nx][ny]);
                            }
                        }
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                for (int k = 0; k <= N + 1; k++) {
                    ans = max(ans, dp[i][j][k]);
                }
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

